	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return base64.RawURLEncoding.EncodeToString(b), nil
}

func buildRedirectURL(redirectPath string, r *http.Request) (string, error) {
	if redirectPath == "" {
		return OAuthConfig.RedirectURL, nil
	}

	u, err := url.Parse(redirectPath)
	if err != nil {
		return "", err
	}

	if u.IsAbs() {
		if u.Scheme != "https" && u.Scheme != "http" {
			return "", errors.New("redirect URL must use http or https")
		}
		return u.String(), nil
	}

