		return "", errors.New("redirect path must start with '/' or be an absolute URL")
	}

	base, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", err
	}

	base.Path = redirectPath
	base.RawQuery = ""
	base.Fragment = ""

	return base.String(), nil
