	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	authURL := OAuthConfig.AuthCodeURL(state)
	return authURL, nil
}

func generateSecureState() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return base64.RawURLEncoding.EncodeToString(b), nil
}

func validateRedirectPath(redirectPath string) (string, error) {
	if redirectPath == "" {
		return "/", nil
	}

	if len(redirectPath) > 2048 {
		return "", errors.New("redirect path too long")
	}

	parsed, err := url.Parse(redirectPath)
	if err != nil {
		return "", errors.New("invalid redirect path")
